import React from 'react';
import Footer from "../components/PageComponents/Footer";
import Navbar from "../components/PageComponents/Navbar";
import NotFoundPage from "../features/NotFoundPage";
import { Typography, Button, Paper, Box, Grid } from '@mui/material';
import useDatasetDetails from '../hooks/useDatasetDetails';

const DetailPage = () => {
    const { dataset, sectionId, handleDownload } = useDatasetDetails();

    if (!dataset) {
        return (
            <div>
                <Navbar />
                <NotFoundPage />
            </div>
        );
    }

    // Function to render a download button
    const renderDownloadButton = (label, url, fileId, fileType) => (
        <Button
            onClick={() => handleDownload(url, fileId, fileType)}
            variant='contained'
            color='primary'
            sx={{ fontFamily: 'monospace', ml: 2 }}  // Adding margin to the left
        >
            {label}
        </Button>
    );

    return (
        <Box sx={{ display: 'flex', flexDirection: 'column', minHeight: '100vh' }}>
            <Navbar />
            <Box component="main" sx={{ flexGrow: 1 }}>
                <Paper sx={{ padding: '20px', marginTop: '20px' }}>
                    <Grid container spacing={2}>

                        {/* Left side: JSON Structure */}
                        <Grid item xs={12} sm={6}>
                            <Typography variant='h5' component='h2' sx={{ fontFamily: 'monospace', fontWeight: 500, marginBottom: '10px' }}>
                                JSON Structure
                            </Typography>
                            <Paper elevation={3} sx={{ padding: '10px', backgroundColor: '#e0e0e0', overflowX: 'auto' }}>
                                <pre style={{ 
                                    fontFamily: 'monospace', 
                                    fontSize: '13px', 
                                    whiteSpace: 'pre-wrap',  
                                    wordWrap: 'break-word',  
                                    margin: 0               
                                }}>
                                    {JSON.stringify(dataset.jsonSnapshot || null, 2)}
                                </pre>
                            </Paper>
                        </Grid>

                        {/* Right side: About and Download Button */}
                        <Grid item xs={12} sm={6}>
                            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
                                <Typography variant='h5' component='h2' sx={{ fontFamily: 'monospace', fontWeight: 500 }}>
                                    About Dataset
                                </Typography>
                                {renderDownloadButton('Download Dataset', dataset.fileUrl, dataset.id, dataset.fileType)}
                                {sectionId.includes('manual') && renderDownloadButton('Download Base Prompt', dataset.fileUrl, dataset.id, dataset.promptType)}
                            </Box>
                            <Typography variant='body1' sx={{ fontFamily: 'monospace' }}>
                                {dataset.description}
                            </Typography>
                        </Grid>
                    </Grid>
                </Paper>
            </Box>
            <Footer />
        </Box>
    );
};

export default DetailPage;
